import{_ as e,o as l,c as a,a2 as d}from"./chunks/framework.Pywvta2k.js";const o=JSON.parse('{"title":"跨医家脏腑辨证索引","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/06-跨病证索引/02-脏腑辨证.md","filePath":"tcm-data/06-跨病证索引/02-脏腑辨证.md","lastUpdated":1781084559000}'),n={name:"tcm-data/06-跨病证索引/02-脏腑辨证.md"};function s(r,t,g,i,x,f){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="跨医家脏腑辨证索引" tabindex="-1">跨医家脏腑辨证索引 <a class="header-anchor" href="#跨医家脏腑辨证索引" aria-label="Permalink to &quot;跨医家脏腑辨证索引&quot;">​</a></h1><blockquote><p>同一脏腑病证，不同医家的不同处理 用于临床参考和交叉验证</p></blockquote><hr><h2 id="脾-胃-系病证" tabindex="-1">脾（胃）系病证 <a class="header-anchor" href="#脾-胃-系病证" aria-label="Permalink to &quot;脾（胃）系病证&quot;">​</a></h2><h3 id="中气虚、脾阳虚" tabindex="-1">中气虚、脾阳虚 <a class="header-anchor" href="#中气虚、脾阳虚" aria-label="Permalink to &quot;中气虚、脾阳虚&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">核心观点</th><th style="text-align:left;">代表方</th><th style="text-align:left;">用药特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>李东垣</strong></td><td style="text-align:left;">内伤脾胃，百病由生</td><td style="text-align:left;">补中益气汤</td><td style="text-align:left;">升阳+补气+少量清热</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">土湿则中轴不转</td><td style="text-align:left;">黄芽汤</td><td style="text-align:left;">参姜苓草，崇阳补土</td></tr><tr><td style="text-align:left;"><strong>彭子益</strong></td><td style="text-align:left;">中气如轴，四维如轮</td><td style="text-align:left;">理中丸类</td><td style="text-align:left;">温中为轴心</td></tr><tr><td style="text-align:left;"><strong>李可</strong></td><td style="text-align:left;">脾阳根于肾阳</td><td style="text-align:left;">四逆汤加味</td><td style="text-align:left;">附子高达30-200g</td></tr></tbody></table><h3 id="湿浊内停" tabindex="-1">湿浊内停 <a class="header-anchor" href="#湿浊内停" aria-label="Permalink to &quot;湿浊内停&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">治法</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">「病痰饮者，当以温药和之」</td><td style="text-align:left;">苓桂术甘汤</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">泄湿燥土，崇阳补火</td><td style="text-align:left;">黄芽汤加茯苓泽泻</td></tr><tr><td style="text-align:left;"><strong>李东垣</strong></td><td style="text-align:left;">升阳除湿</td><td style="text-align:left;">升阳除湿汤</td></tr></tbody></table><hr><h2 id="肝-胆-系病证" tabindex="-1">肝（胆）系病证 <a class="header-anchor" href="#肝-胆-系病证" aria-label="Permalink to &quot;肝（胆）系病证&quot;">​</a></h2><h3 id="肝郁" tabindex="-1">肝郁 <a class="header-anchor" href="#肝郁" aria-label="Permalink to &quot;肝郁&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">治法</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">疏肝理脾</td><td style="text-align:left;">四逆散（柴胡、枳实、芍药、甘草）</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">达木扶阳，风木宜疏</td><td style="text-align:left;">桂枝+白芍为主</td></tr><tr><td style="text-align:left;"><strong>朱震亨</strong></td><td style="text-align:left;">六郁同治</td><td style="text-align:left;">越鞠丸（气郁为主）</td></tr><tr><td style="text-align:left;"><strong>李辛</strong></td><td style="text-align:left;">能量郁结，该开不开</td><td style="text-align:left;">运动+情绪疏导+中药</td></tr></tbody></table><h3 id="肝血虚" tabindex="-1">肝血虚 <a class="header-anchor" href="#肝血虚" aria-label="Permalink to &quot;肝血虚&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">治法</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">养血柔肝</td><td style="text-align:left;">酸枣仁汤</td></tr><tr><td style="text-align:left;"><strong>钱乙</strong></td><td style="text-align:left;">滋水涵木</td><td style="text-align:left;">六味地黄丸</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">乌肝汤法</td><td style="text-align:left;">当归、首乌、白芍、桂枝</td></tr><tr><td style="text-align:left;"><strong>张锡纯</strong></td><td style="text-align:left;">镇肝熄风</td><td style="text-align:left;">镇肝熄风汤</td></tr></tbody></table><h3 id="肝阳上亢-相火不降-高血压" tabindex="-1">肝阳上亢 / 相火不降（高血压） <a class="header-anchor" href="#肝阳上亢-相火不降-高血压" aria-label="Permalink to &quot;肝阳上亢 / 相火不降（高血压）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">病机认识</th><th style="text-align:left;">治法</th><th style="text-align:left;">代表方</th><th style="text-align:left;">对普光相关</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">水寒土湿木郁，相火不降</td><td style="text-align:left;">温下潜上</td><td style="text-align:left;">金鼎汤</td><td style="text-align:left;">✅ <strong>最符合普光病机</strong></td></tr><tr><td style="text-align:left;"><strong>张锡纯</strong></td><td style="text-align:left;">肝阳上亢，气血逆上</td><td style="text-align:left;">镇肝熄风</td><td style="text-align:left;">镇肝熄风汤</td><td style="text-align:left;">部分吻合</td></tr><tr><td style="text-align:left;"><strong>朱震亨</strong></td><td style="text-align:left;">阴虚相火妄动</td><td style="text-align:left;">滋阴降火</td><td style="text-align:left;">大补阴丸</td><td style="text-align:left;">❌ 不适合普光</td></tr><tr><td style="text-align:left;"><strong>李可</strong></td><td style="text-align:left;">下寒上热，火不归原</td><td style="text-align:left;">温潜</td><td style="text-align:left;">温氏奔豚汤</td><td style="text-align:left;">✅ <strong>高度吻合</strong></td></tr></tbody></table><hr><h2 id="肾-膀胱-系病证" tabindex="-1">肾（膀胱）系病证 <a class="header-anchor" href="#肾-膀胱-系病证" aria-label="Permalink to &quot;肾（膀胱）系病证&quot;">​</a></h2><h3 id="肾阳虚" tabindex="-1">肾阳虚 <a class="header-anchor" href="#肾阳虚" aria-label="Permalink to &quot;肾阳虚&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">治法</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">温补肾阳</td><td style="text-align:left;">八味肾气丸</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">天魂汤法温肾水</td><td style="text-align:left;">附子+干姜+参苓</td></tr><tr><td style="text-align:left;"><strong>李可</strong></td><td style="text-align:left;">大剂量附子破阴寒</td><td style="text-align:left;">四逆汤类</td></tr><tr><td style="text-align:left;"><strong>张介宾</strong></td><td style="text-align:left;">温补命门</td><td style="text-align:left;">右归丸</td></tr></tbody></table><h3 id="肾阴虚" tabindex="-1">肾阴虚 <a class="header-anchor" href="#肾阴虚" aria-label="Permalink to &quot;肾阴虚&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">治法</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>钱乙</strong></td><td style="text-align:left;">滋补肾阴</td><td style="text-align:left;">六味地黄丸</td></tr><tr><td style="text-align:left;"><strong>朱震亨</strong></td><td style="text-align:left;">滋阴降火</td><td style="text-align:left;">大补阴丸</td></tr><tr><td style="text-align:left;"><strong>张介宾</strong></td><td style="text-align:left;">填补精血</td><td style="text-align:left;">左归丸</td></tr></tbody></table><hr><h2 id="心系病证" tabindex="-1">心系病证 <a class="header-anchor" href="#心系病证" aria-label="Permalink to &quot;心系病证&quot;">​</a></h2><h3 id="失眠" tabindex="-1">失眠 <a class="header-anchor" href="#失眠" aria-label="Permalink to &quot;失眠&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">病机</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">虚烦不得眠</td><td style="text-align:left;">酸枣仁汤</td></tr><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">少阴热化</td><td style="text-align:left;">黄连阿胶汤</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">相火不降，水火不交</td><td style="text-align:left;">金鼎汤（龙牡+半夏）</td></tr><tr><td style="text-align:left;"><strong>彭子益</strong></td><td style="text-align:left;">胆经相火不降</td><td style="text-align:left;">温胆汤</td></tr><tr><td style="text-align:left;"><strong>李辛</strong></td><td style="text-align:left;">能量该阖不阖</td><td style="text-align:left;">降相火+早休息</td></tr></tbody></table><h3 id="高血压的跨医家对比" tabindex="-1">高血压的跨医家对比 <a class="header-anchor" href="#高血压的跨医家对比" aria-label="Permalink to &quot;高血压的跨医家对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">病机</th><th style="text-align:left;">治法</th><th style="text-align:left;">方例</th><th style="text-align:left;">适合普光吗？</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">水寒土湿、相火不降</td><td style="text-align:left;">温下焦、潜上焦</td><td style="text-align:left;">金鼎汤、黄芽汤</td><td style="text-align:left;">✅ <strong>最佳匹配</strong></td></tr><tr><td style="text-align:left;"><strong>李可</strong></td><td style="text-align:left;">阳虚于下，火浮于上</td><td style="text-align:left;">温潜</td><td style="text-align:left;">温氏奔豚汤</td><td style="text-align:left;">✅ <strong>高度匹配</strong></td></tr><tr><td style="text-align:left;"><strong>张锡纯</strong></td><td style="text-align:left;">肝阳上亢，气血逆上</td><td style="text-align:left;">镇肝熄风</td><td style="text-align:left;">镇肝熄风汤</td><td style="text-align:left;">⚠️ 部分匹配</td></tr><tr><td style="text-align:left;"><strong>朱震亨</strong></td><td style="text-align:left;">阴虚相火妄动</td><td style="text-align:left;">滋阴降火</td><td style="text-align:left;">大补阴丸</td><td style="text-align:left;">❌ 不匹配</td></tr><tr><td style="text-align:left;"><strong>倪海厦</strong></td><td style="text-align:left;">三焦不通</td><td style="text-align:left;">经方随证治之</td><td style="text-align:left;">真武汤等</td><td style="text-align:left;">需辨证</td></tr></tbody></table><hr><h2 id="妇科-普明相关" tabindex="-1">妇科（普明相关） <a class="header-anchor" href="#妇科-普明相关" aria-label="Permalink to &quot;妇科（普明相关）&quot;">​</a></h2><h3 id="月经先期" tabindex="-1">月经先期 <a class="header-anchor" href="#月经先期" aria-label="Permalink to &quot;月经先期&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">病机认识</th><th style="text-align:left;">治法</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">冲任虚寒，或瘀血内停</td><td style="text-align:left;">温经汤/桂枝茯苓丸</td><td style="text-align:left;">温经汤</td></tr><tr><td style="text-align:left;"><strong>傅青主</strong></td><td style="text-align:left;">血热或气虚</td><td style="text-align:left;">清经散/两地汤</td><td style="text-align:left;">清经散</td></tr><tr><td style="text-align:left;"><strong>朱震亨</strong></td><td style="text-align:left;">相火妄动，热迫血行</td><td style="text-align:left;">滋阴降火</td><td style="text-align:left;">大补阴丸加减</td></tr><tr><td style="text-align:left;"><strong>李辛</strong></td><td style="text-align:left;">下焦封藏不住</td><td style="text-align:left;">补肾固摄</td><td style="text-align:left;">熟地+山萸+杜仲</td></tr></tbody></table><h3 id="白带异常" tabindex="-1">白带异常 <a class="header-anchor" href="#白带异常" aria-label="Permalink to &quot;白带异常&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">治法</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">温化寒湿</td><td style="text-align:left;">当归芍药散</td></tr><tr><td style="text-align:left;"><strong>傅青主</strong></td><td style="text-align:left;">健脾祛湿</td><td style="text-align:left;">完带汤</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">土湿木郁，湿浊下注</td><td style="text-align:left;">茯苓+泽泻+黄柏</td></tr></tbody></table><hr><h2 id="脾肾阳虚-上热下寒-——-您和普明的核心病机对比" tabindex="-1">脾肾阳虚（上热下寒）—— <strong>您和普明的核心病机对比</strong> <a class="header-anchor" href="#脾肾阳虚-上热下寒-——-您和普明的核心病机对比" aria-label="Permalink to &quot;脾肾阳虚（上热下寒）—— **您和普明的核心病机对比**&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">普光（男）</th><th style="text-align:left;">普明（女）</th></tr></thead><tbody><tr><td style="text-align:left;">上热表现</td><td style="text-align:left;">口渴、前胸出汗、血压高</td><td style="text-align:left;">潮热、烦躁、口干</td></tr><tr><td style="text-align:left;">下寒表现</td><td style="text-align:left;">腰凉、脚冷、阴囊湿</td><td style="text-align:left;">手脚冷、经期腰凉</td></tr><tr><td style="text-align:left;">中虚表现</td><td style="text-align:left;">无力、头前倾</td><td style="text-align:left;">疲惫、腹胀、便秘</td></tr><tr><td style="text-align:left;">核心区别</td><td style="text-align:left;">寒湿重+湿热下注</td><td style="text-align:left;">血虚+中虚+相火浮越</td></tr><tr><td style="text-align:left;">适合医家</td><td style="text-align:left;">黄元御+李可（温阳潜降）</td><td style="text-align:left;">黄元御+傅青主+李辛（培中养血潜降）</td></tr><tr><td style="text-align:left;">核心方</td><td style="text-align:left;"><strong>温潜黄芽天魂汤</strong></td><td style="text-align:left;"><strong>加减黄芽地魄汤</strong></td></tr></tbody></table><hr><p><em>本索引可在后续开发中按病证（如高血压、失眠、腰痛）、按症状（如口渴、出汗、怕冷）进一步细分。</em></p>',39)])])}const h=e(n,[["render",s]]);export{o as __pageData,h as default};
